import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { getDocuments, deleteDocument } from '../services/documentService';
import { useAuth } from '../services/authService';

const getFileExtension = (filename = '') => {
  return filename.split('.').pop().toUpperCase() || 'FILE';
};

const extColor = (ext) => {
  const map = {
    PDF: 'from-red-500/20 to-red-600/10 border-red-500/30 text-red-400',
    DOCX: 'from-blue-500/20 to-blue-600/10 border-blue-500/30 text-blue-400',
    DOC: 'from-blue-500/20 to-blue-600/10 border-blue-500/30 text-blue-400',
    XLSX: 'from-green-500/20 to-green-600/10 border-green-500/30 text-green-400',
    XLS: 'from-green-500/20 to-green-600/10 border-green-500/30 text-green-400',
    TXT: 'from-slate-500/20 to-slate-600/10 border-slate-500/30 text-slate-400',
  };
  return map[ext] || 'from-accent-indigo/20 to-accent-violet/10 border-accent-indigo/30 text-accent-indigo';
};

const DocumentList = () => {
  const { user } = useAuth();
  const [documents, setDocuments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [search, setSearch] = useState('');
  const isAdmin = user?.roles?.some(r => r.name === 'ROLE_ADMIN');

  useEffect(() => { fetchDocuments(); }, []);

  const fetchDocuments = async () => {
    try {
      const data = await getDocuments();
      setDocuments(data);
    } catch (err) {
      setError('Failed to fetch documents');
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (documentId) => {
    if (window.confirm('Are you sure you want to delete this document?')) {
      try {
        await deleteDocument(documentId);
        setDocuments(documents.filter(doc => doc.id !== documentId));
      } catch (err) {
        setError('Failed to delete document');
      }
    }
  };

  const filtered = documents.filter(d =>
    d.title?.toLowerCase().includes(search.toLowerCase()) ||
    d.description?.toLowerCase().includes(search.toLowerCase())
  );

  if (loading) {
    return (
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-20 text-center">
        <div className="inline-flex items-center gap-3 text-slate-400">
          <svg className="animate-spin h-6 w-6 text-accent-indigo" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
          <span className="text-lg font-medium">Loading your documents...</span>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-8">
        <div>
          <h1 className="text-3xl font-extrabold text-white tracking-tight">
            {isAdmin ? 'Global Repository' : 'My Documents'}
          </h1>
          <p className="text-slate-400 text-sm mt-1">{documents.length} document{documents.length !== 1 ? 's' : ''} total</p>
        </div>
        <Link to="/upload" className="btn-premium py-3 px-6 flex-shrink-0">
          <svg className="mr-2 h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
          </svg>
          Upload New
        </Link>
      </div>

      {/* Search */}
      <div className="relative mb-8">
        <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
          <svg className="h-5 w-5 text-slate-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
          </svg>
        </div>
        <input
          type="text"
          value={search}
          onChange={e => setSearch(e.target.value)}
          placeholder="Search documents by title or description..."
          className="form-input-premium pl-12 max-w-lg"
        />
      </div>

      {error && (
        <div className="mb-6 bg-red-500/10 border border-red-500/30 rounded-xl p-4 flex items-center gap-3">
          <svg className="h-5 w-5 text-red-400 flex-shrink-0" fill="currentColor" viewBox="0 0 20 20">
            <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" />
          </svg>
          <p className="text-sm text-red-400 font-medium">{error}</p>
        </div>
      )}

      {filtered.length === 0 ? (
        <div className="glass-card py-24 text-center">
          <div className="w-20 h-20 mx-auto bg-white/5 rounded-3xl flex items-center justify-center mb-6 border border-white/10">
            <svg className="h-10 w-10 text-slate-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M9 13h6m-3-3v6m5 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
            </svg>
          </div>
          <h3 className="text-xl font-bold text-white mb-2">No documents found</h3>
          <p className="text-slate-400 text-sm mb-8">
            {search ? `No results for "${search}"` : 'Get started by uploading your first document.'}
          </p>
          <Link to="/upload" className="btn-premium py-3 px-8 inline-flex">
            Upload your first document
          </Link>
        </div>
      ) : (
        <div className="grid grid-cols-1 gap-5 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4">
          {filtered.map((doc) => {
            const ext = getFileExtension(doc.fileName || doc.title);
            const colors = extColor(ext);
            return (
              <div key={doc.id} className="glass-card glass-card-hover flex flex-col">
                <div className="p-5 flex-1">
                  <div className="flex items-start justify-between mb-4">
                    <div className={`w-12 h-12 rounded-xl bg-gradient-to-br ${colors} border flex items-center justify-center flex-shrink-0`}>
                      <svg className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 21h10a2 2 0 002-2V9.414a1 1 0 00-.293-.707l-5.414-5.414A1 1 0 0012.586 3H7a2 2 0 00-2 2v14a2 2 0 002 2z" />
                      </svg>
                    </div>
                    <span className="inline-flex items-center px-2 py-0.5 rounded-md text-[11px] font-bold bg-white/5 border border-white/10 text-slate-400 uppercase tracking-wider">
                      {ext}
                    </span>
                  </div>
                  <h4 className="text-base font-bold text-white truncate mb-1" title={doc.title}>{doc.title}</h4>
                  <p className="text-sm text-slate-500 line-clamp-2 mb-4 h-10">{doc.description || 'No description provided.'}</p>
                  <div className="flex items-center text-xs text-slate-600 gap-1.5">
                    <svg className="h-3.5 w-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" />
                    </svg>
                    {new Date(doc.uploadDate).toLocaleDateString(undefined, { year: 'numeric', month: 'short', day: 'numeric' })}
                  </div>
                </div>
                <div className="px-5 py-4 border-t border-white/5 flex gap-2">
                  <button
                    onClick={() => window.open(`/api/documents/download/${doc.id}`, '_blank')}
                    className="flex-1 inline-flex justify-center items-center gap-2 px-3 py-2.5 text-sm font-semibold rounded-lg bg-white/5 hover:bg-white/10 border border-white/10 hover:border-accent-indigo/40 text-slate-300 hover:text-white transition-all"
                  >
                    <svg className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                    </svg>
                    Download
                  </button>
                  <button
                    onClick={() => handleDelete(doc.id)}
                    className="inline-flex justify-center items-center px-3 py-2.5 rounded-lg bg-red-500/10 hover:bg-red-500/20 border border-red-500/20 hover:border-red-500/40 text-red-400 hover:text-red-300 transition-all"
                    title="Delete"
                  >
                    <svg className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                    </svg>
                  </button>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
};

export default DocumentList;
